module adder_pipe_64bit
(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output reg [64:0] result,
    output reg o_en
);
// Internal pipeline registers
reg [63:0] adda_reg [0:2];
reg [63:0] addb_reg [0:2];
reg carry_reg [0:2];
reg i_en_reg;
// Combinational logic
wire [63:0] sum_stage [0:1];
wire [64:0] carry_stage [0:1];
// Pipeline stages
assign sum_stage[0] = adda_reg[0] ^ addb_reg[0]; // XOR operation for the sum at pipeline stage 0.
assign carry_stage[0] = {1'b0, (adda_reg[0] & addb_reg[0])}; // AND operation for the carry at pipeline stage 0.
assign sum_stage[1] = sum_stage[0] ^ carry_stage[0][63:0]; // XOR operation for the sum at pipeline stage 1.
assign carry_stage[1] = {1'b0, (sum_stage[0] & carry_stage[0][63:0])} + carry_stage[0]; // AND and addition operation for the carry at pipeline stage 1.
// Pipeline registers update logic
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        adda_reg[0] <= 64'b0;
        addb_reg[0] <= 64'b0;
        carry_reg[0] <= 65'b0;
        adda_reg[1] <= 64'b0;
        addb_reg[1] <= 64'b0;
        carry_reg[1] <= 65'b0;
        adda_reg[2] <= 64'b0;
        addb_reg[2] <= 64'b0;
        carry_reg[2] <= 65'b0;
        i_en_reg <= 1'b0;
        o_en <= 1'b0;
        result <= 65'b0;
    end else begin
        adda_reg[0] <= adda;
        addb_reg[0] <= addb;
        carry_reg[0] <= carry_stage[0];

        adda_reg[1] <= adda_reg[0];
        addb_reg[1] <= addb_reg[0];
        carry_reg[1] <= carry_reg[0];

        adda_reg[2] <= adda_reg[1];
        addb_reg[2] <= addb_reg[1];
        carry_reg[2] <= carry_reg[1];
        i_en_reg <= i_en;
        o_en <= carry_reg[2][64];
        result <= carry_reg[2][63:0];
    end
end
endmodule
